#include<bits/stdc++.h>
using namespace std;
string s1,s2;
int ans,a[27],b[27];
int main(){
    cin>>s1>>s2;
    for(int i=0;i<s1.size();i++) a[(int)(s1[i]-'a'+1)]++;
    for(int i=0;i<s2.size();i++) b[(int)(s2[i]-'a'+1)]++;
    for(int i=1;i<=26;i++) ans+=min(a[i],b[i]);
    cout<<ans;
    return 0;
}
